here is a nice pagination template i've worked up.
```html
<div >
	<p><a ng-click="selectPage(1)" onclick="btnFirst_Click();return false;">&larr;&larr;FIRST</a>||
	<a ng-click="selectPage((currentPage-1))"
		onclick="btnPrev_Click();return false;">&larr;PREV</a>&nbsp;<select
		id="pageNumList"><option
			ng-repeat="n in [] | range: numPages" ng-click="selectPage(n)"
			value="{{n}}">{{n}}</option></select>
	/{{numPages}}


	<a ng-click="selectPage((currentPage + 1))"
		onclick="btnNext_Click();return false;">NEXT&rarr;</a>||<a
		ng-click="selectPage(numPages)"
		onclick="btnLast_Click();return false;">LAST&rarr;&rarr;</a>
		</p>
</div>
```
```javascript
<script>
	function btnPrev_Click() {
		var selectedIndex = $("#pageNumList").prop("selectedIndex");
		if (selectedIndex > 0) {
			$("#pageNumList").prop("selectedIndex", selectedIndex - 1);
		}
	};
	function btnFirst_Click() {
		var selectedIndex = $("#pageNumList").prop("selectedIndex");
		$("#pageNumList").prop("selectedIndex", 0);

	};
	function btnNext_Click() {
		//  Note:  the JQuery "prop" function requires JQuery v1.6 or later
		var selectedIndex = $("#pageNumList").prop("selectedIndex");
		var itemsInDropDownList = $("#pageNumList option").length;
		//  If we're not already selecting the last item in the drop down list, then increment the SelectedIndex
		if (selectedIndex < (itemsInDropDownList - 1)) {
			$("#pageNumList").prop("selectedIndex", selectedIndex + 1);
		}
	};

	function btnLast_Click() {
		var selectedIndex = $("#pageNumList").prop("selectedIndex");
		var itemsInDropDownList = $("#pageNumList option").length;
		$("#pageNumList").prop("selectedIndex", (itemsInDropDownList - 1));

	};
</script>
